class AttentionFusion(nn.Module): #不分组处理
    def __init__(self, channels, out_channels, stride):
        super(AttentionFusion, self).__init__()
        self.channels = channels

        # 通道注意力（SE Block 风格）
        self.global_pool = nn.AdaptiveAvgPool2d((1, 1))
        self.channel_fc = nn.Sequential(
            nn.Conv2d(channels, channels // 4, kernel_size=1, bias=False),
            nn.ReLU(inplace=True),
            nn.Conv2d(channels // 4, channels, kernel_size=1, bias=False),
            nn.Sigmoid()
        )

        # 空间注意力（水平和垂直）
        self.spatial_conv1x1 = nn.Conv2d(channels, channels, kernel_size=1)
        self.local_conv = nn.Conv2d(channels, channels, kernel_size=3, padding=1)

        # 替换为 BatchNorm
        self.bn_main = nn.BatchNorm2d(channels)
        self.bn_local = nn.BatchNorm2d(channels)
        self.bn_fuse = nn.BatchNorm2d(out_channels)

        self.act_local = nn.SiLU()
        self.act_fusion = nn.SiLU()

        # 融合通道
        self.conv_fuse = nn.Conv2d(channels, out_channels, kernel_size=3, stride=stride, padding=1)

    def forward(self, x):
        b, c, h, w = x.size()

        # 通道注意力增强
        chn_att = self.channel_fc(self.global_pool(x))  # [B, C, 1, 1]
        x = x * chn_att  # 通道增强

        # 空间注意力（水平+垂直）
        x_h = F.adaptive_avg_pool2d(x, (h, 1))  # [B, C, H, 1]
        x_w = F.adaptive_avg_pool2d(x, (1, w))  # [B, C, 1, W]
        x_w = x_w.permute(0, 1, 3, 2)           # [B, C, W, 1]
        spatial = torch.cat([x_h, x_w], dim=2)  # [B, C, H+W, 1]

        spatial_att = self.spatial_conv1x1(spatial)  # [B, C, H+W, 1]
        attn_h, attn_w = torch.split(spatial_att, [h, w], dim=2)
        attn_h = attn_h.sigmoid()  # [B, C, H, 1]
        attn_w = attn_w.permute(0, 1, 3, 2).sigmoid()  # [B, C, 1, W]

        # 应用空间注意力
        x_CA = self.bn_main(x * attn_h * attn_w)

        # 局部增强分支（卷积）
        x_local = self.act_local(self.bn_local(self.local_conv(x)))

        # 特征融合
        x_out = self.act_fusion(self.bn_fuse(self.conv_fuse(x_CA + x_local)))

        return x_out

class DepthWiseSeparableConv2d(nn.Sequential):
    """Depthwise Separable Convolution followed by pointwise 1x1 Convolution.

    A convolution is called depthwise separable when the normal convolution is split into two convolutions:
    depthwise convolution and pointwise convolution.

    Args:
        in_channels (int): number of input channels
        out_channels (int): number of output channels
        kernel_size (int): separable conv receptive field
        stride (int): separable conv stride.
        padding (int): separable conv padding.
        depth_multiplier (int): Factor by which we multiply the *in_channels* to get the number of output_channels
            in the depthwise convolution.
        **kwargs: Additional keyword arguments passed to the first convolution operator.
    """

    def __init__(self, in_channels, out_channels, kernel_size=1, stride=1, padding=0, dilation=1, bias=False,
                 depth_multiplier=1,
                 **kwargs):
        super(DepthWiseSeparableConv2d, self).__init__(
            nn.Conv2d(in_channels, int(in_channels * depth_multiplier), kernel_size=kernel_size, stride=stride,
                      padding=padding, dilation=dilation, groups=in_channels, bias=bias, **kwargs),
            nn.Conv2d(int(depth_multiplier * in_channels), out_channels, kernel_size=1, stride=1, padding=0,
                      dilation=1, groups=1, bias=bias)
        )


class ConvLayer(nn.Sequential):
    """Building Block Convolution Layer

    Args:
        in_channels (int): number of input channels
        out_channels (int): number of output channels
        kernel_size (int): conv receptive field
        stride (int): conv stride
        dilation (int): conv dilation
        bias (bool): whether or not to add a bias
        norm (str): type of the normalization
        activation (str): type of non-linear activation
        separable (bool): whether to use separable convolution
        **kwargs: Additional keyword arguments passed to the convolution operator.
    """

    def __init__(self, in_channels, out_channels,
                 kernel_size=3, stride=1, padding=1, dilation=1,
                 bias=True, norm="BatchNorm2d", activation='ReLU', separable=False, **kwargs): #这里默认的激活函数从ReLU换成了SiLU

        conv_func = DepthWiseSeparableConv2d if separable else nn.Conv2d
        self.out_channels = out_channels
        self.separable = separable
        if not separable and "depth_multiplier" in kwargs:
            kwargs.pop('depth_multiplier')

        normalizer = nn.Identity() if norm == 'none' else getattr(nn, norm)(out_channels)

        super(ConvLayer, self).__init__(
            conv_func(in_channels, out_channels, kernel_size=kernel_size, stride=stride, dilation=dilation,
                      padding=padding, bias=bias, **kwargs),
            normalizer,
            getattr(nn, activation)()
        )


class PreActBlock(nn.Module):
    """
    Squeeze-Excite Block from:
    Squeeze-and-Excitation Networks (Hu et al.)

    Args:
        in_channels (int): number of input channels.
        out_channels (int): number of output channels.
        stride (int): convolution stride.
    """

    def __init__(self, in_channels, out_channels, stride=1):
        assert out_channels % 4 == 0
        super(PreActBlock, self).__init__()
        self.conv1 = ConvLayer(in_channels, out_channels,
                               kernel_size=3, stride=stride, padding=1, bias=False)
        self.conv2 = ConvLayer(out_channels, out_channels,
                               kernel_size=3, stride=1, padding=1, bias=False)
        self.downsample = nn.Sequential()
        if stride != 1 or in_channels != out_channels:
            self.downsample = nn.Sequential(
                nn.Conv2d(in_channels, out_channels,
                          kernel_size=1, stride=stride, padding=0, bias=False)
            )
        # SE layers
        self.fc1 = nn.Conv2d(out_channels, out_channels // 4, kernel_size=1)
        self.fc2 = nn.Conv2d(out_channels // 4, out_channels, kernel_size=1)
        self.out_channels = out_channels

    def forward(self, x):
        out = self.conv1(x) #in_channels->out_channels ; 如果striide=2 那么高宽减半
        out = self.conv2(out) # out_channels->out_channels ; 高宽不变
        # Squeeze
        w = F.adaptive_avg_pool2d(out, (1, 1)) #前两个维度保留，最后两个维度变为(1,1),即只保留hw空间维度上的平均值 (tn,out_channels,1,1)
        w = F.relu(self.fc1(w)) #[tn, out_channels//4, 1,1]
        w = torch.sigmoid(self.fc2(w)) #[tn, out_channels,1,1] 归一化至0-1
        # Excitation
        out = out * w
        out = out + self.downsample(x)
        return out

class FEBlock(nn.Module):
    def __init__(self, in_channels, out_channels, stride=1):
        super(FEBlock, self).__init__()
        assert out_channels % 4 == 0

        # self.conv1 = ConvLayer(in_channels, out_channels,
        #                        kernel_size=3, stride=stride, padding=1, bias=False)
        # self.conv2 = ConvLayer(out_channels, out_channels,
        #                        kernel_size=3, stride=1, padding=1, bias=False)

        self.downsample = nn.Sequential()
        if stride != 1 or in_channels != out_channels:
            self.downsample = nn.Sequential(
                nn.Conv2d(in_channels, out_channels,
                          kernel_size=1, stride=stride, padding=0, bias=False)
            )

        # # 用 AttentionFusion 替代原始 SE 模块
        # self.attn = AttentionFusion(out_channels)
        self.attn = AttentionFusion(in_channels, out_channels, stride)

    def forward(self, x):
        # out = self.conv1(x)
        # out = self.conv2(out)
        # out = self.attn(out)
        # out = out + self.downsample(x)
        # return out
        out = self.attn(x)
        out = out + self.downsample(x)
        return out

class ResBlock(nn.Module):
    """
    Residual Convolutional Block

    Args:
        in_channels (int): number of input channels
        out_channels (int): number of output channels
        stride (int): convolutional stride
        norm (str): type of normalization
    """

    def __init__(self, in_channels, out_channels, stride=1, norm="BatchNorm2d"):
        super(ResBlock, self).__init__()
        bias = norm == 'none'
        self.in_channels = in_channels
        self.out_channels = out_channels
        self.conv1 = ConvLayer(
            in_channels=in_channels,
            out_channels=out_channels,
            kernel_size=3,
            padding=1,
            bias=bias,
            norm=norm,
        )
        self.conv2 = ConvLayer(
            in_channels=out_channels,
            out_channels=out_channels,
            kernel_size=3,
            stride=stride,
            padding=1,
            norm=norm,
            bias=False,
        )

        self.downsample = nn.Sequential()
        if stride != 1 or in_channels != out_channels:
            self.downsample = ConvLayer(
                in_channels=in_channels,
                out_channels=out_channels,
                kernel_size=1,
                padding=0,
                stride=stride,
                norm=norm,
                bias=False,
                activation="Identity",
            )

    def forward(self, x):
        out = self.conv1(x)
        out = self.conv2(out)
        out = out + self.downsample(x)
        out = F.relu(out)
        return out
